def test_flatten_dict_nested():
    """Test flattening of nested dictionaries."""
    input_dict = {
        'a': 1,
        'b': {
            'c': 2,
            'd': {
                'e': 3
            }
        }
    }
    expected = {
        'a': 1,
        'b.c': 2,
        'b.d.e': 3
    }
    assert flatten_dict(input_dict) == expected


